'use client'
import { cn, Slot } from '@cascivo/core'
import type { ButtonHTMLAttributes } from 'react'
import { Spinner } from '../spinner/spinner'
import styles from './button.module.css'

export interface ButtonProps extends ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'ghost' | 'destructive'
  size?: 'sm' | 'md' | 'lg'
  loading?: boolean
  /**
   * Render the single child element instead of a native `<button>` so the button
   * styling lands on, e.g., a real `<a href>` (preserves middle-click / open-in-new-tab).
   * The child owns its own content; the loading spinner is not rendered in this mode.
   */
  asChild?: boolean
}

export function Button({
  variant = 'primary',
  size = 'md',
  loading = false,
  asChild = false,
  className,
  disabled,
  children,
  ...props
}: ButtonProps) {
  const shared = {
    'data-variant': variant,
    'data-size': size,
    'data-state': loading ? 'loading' : 'idle',
    'aria-busy': loading || undefined,
    className: cn(styles['button'], className),
  }

  if (asChild) {
    return (
      <Slot {...shared} {...props}>
        {children}
      </Slot>
    )
  }

  return (
    <button {...shared} disabled={disabled || loading} {...props}>
      {loading && <Spinner size="sm" aria-hidden="true" />}
      <span>{children}</span>
    </button>
  )
}

@layer cascivo.component {
  .button {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    gap: var(--cascivo-space-2);
    font-family: var(--cascivo-font-sans);
    font-weight: var(--cascivo-font-medium);
    line-height: var(--cascivo-leading-none);
    white-space: nowrap;
    cursor: pointer;
    border: 1px solid transparent;
    transition:
      background-color var(--cascivo-duration-150) var(--cascivo-ease-out),
      color var(--cascivo-duration-150) var(--cascivo-ease-out),
      box-shadow var(--cascivo-duration-150) var(--cascivo-ease-out);
    border-radius: var(--cascivo-button-radius, var(--cascivo-radius-control));

    &:focus-visible {
      outline: none;
      box-shadow: var(--cascivo-focus-ring);
    }

    &:disabled {
      opacity: 0.5; /* static fallback */
      opacity: var(--cascivo-disabled-opacity, 0.5);
      cursor: not-allowed;
      pointer-events: none;
    }

    /* Sizes */
    &[data-size='sm'] {
      height: var(--cascivo-control-height-sm);
      padding-inline: var(--cascivo-space-3);
      font-size: var(--cascivo-text-ui); /* canonical control-label role (= text-sm) */
    }

    &[data-size='md'] {
      height: var(--cascivo-control-height-md);
      padding-inline: var(--cascivo-space-4);
      padding-block: 0.5rem; /* static fallback — non-supporting browsers */
      padding-block: --cascivo-step(2); /* progressive enhancement — Chrome 133+ */
      font-size: var(--cascivo-text-ui); /* canonical control-label role (= text-sm) */
    }

    &[data-size='lg'] {
      height: var(--cascivo-control-height-lg);
      padding-inline: var(--cascivo-space-6);
      font-size: var(--cascivo-text-body); /* larger control label (= text-base) */
    }

    /* Coarse-pointer touch targets — raise minimum to 44px, desktop density unchanged */
    @media (pointer: coarse) {
      &[data-size='sm'] {
        min-block-size: var(--cascivo-target-min-coarse, 2.75rem);
      }
      &[data-size='md'] {
        min-block-size: var(--cascivo-target-min-coarse, 2.75rem);
      }
    }

    /* Variants */
    &[data-variant='primary'] {
      background-color: var(--cascivo-color-primary);
      color: var(--cascivo-color-primary-fg);

      &:hover:not(:disabled) {
        background-color: var(--cascivo-color-primary-hover);
      }

      &:active:not(:disabled) {
        background-color: var(--cascivo-color-primary-active);
      }
    }

    &[data-variant='secondary'] {
      background-color: var(--cascivo-color-secondary);
      color: var(--cascivo-color-secondary-content);

      &:hover:not(:disabled) {
        background-color: var(--cascivo-color-secondary-hover);
      }
    }

    &[data-variant='ghost'] {
      background-color: transparent;
      color: var(--cascivo-color-text);

      &:hover:not(:disabled) {
        background-color: var(--cascivo-color-bg-subtle);
      }
    }

    &[data-variant='destructive'] {
      background-color: var(--cascivo-color-destructive);
      color: var(--cascivo-color-text-on-destructive);

      &:hover:not(:disabled) {
        background-color: var(--cascivo-color-destructive-hover);
      }
    }
  }
}

@media (forced-colors: active) {
  .button {
    border: 1px solid ButtonText;
  }

  .button:focus-visible {
    outline: 2px solid Highlight;
    outline-offset: 2px;
  }

  .button:disabled {
    border-color: GrayText;
    color: GrayText;
  }
}
